/* The file defining the AST classes including the visitor interface, except for AST classes that are Token classes 
 * as well. */

/** AST ::= BoolConstant | IntConstant | EmptyConstant | Variable | PrimFun | UnOpApp | BinOpApp | App | Map | If | Let */

/** AST class definitions */

/** The AST type which support a visitor interface */
interface AST {
  public <ResType> ResType accept(ASTVisitor<ResType> v);
}

interface ASTVisitor<ResType> {
  ResType forBoolConstant(BoolConstant b);
  ResType forIntConstant(IntConstant i);
  ResType forEmptyConstant(EmptyConstant n);
  ResType forVariable(Variable v);
  ResType forPrimFun(PrimFun f);
  ResType forUnOpApp(UnOpApp u);
  ResType forBinOpApp(BinOpApp b);
  ResType forApp(App a);
  ResType forMap(Map m);
  ResType forIf(If i);
  ResType forLet(Let l);
  ResType forBlock(Block b);
}

/* The Term interface correspond to AST's that when output as concrete syntax by toString() can be used as terms 
 * in an iterative binary expression without enclosing parentheses. We enclose all binary expressions in parentheses
 * so we do not presume either left or right associativity for infix binary operators. */
/** Term ::= Constant | PrimFun | Variable | UnOpApp |  App */
interface Term extends AST {}

/* NOTE: all Constant objects belong to the types Token and AST; Constant tokens evaluate to themselves.
 * The variant classes (IntConstant, BoolConstant, EmptyConstant) are defined in the file ValuesTokens.java */

/** Constant ::= IntConstant | BoolConstant | EmptyConstant */
interface Constant extends Term {}

/** UnOp ::= UnOpPlus | UnOpMinus | OpTilde */
/** Class representing the unary operator within a UnOppApp. */
abstract class UnOp {
  String name;
  public UnOp(String s) { name = s; }
  public String toString() { return name; }
  public abstract <ResType> ResType accept(UnOpVisitor<ResType> v);
}

/** Visitor for the UnOp union type. */
interface UnOpVisitor<ResType> {
  ResType forUnOpPlus();
  ResType forUnOpMinus();
  ResType forOpTilde();
  ResType forOpBang();
  ResType forOpRef();
}

/** BinOp ::= BinOpPlus | BinOpMinus | OpTimes | OpDivide | OpEquals | OpNotEquals | OpLessThan | OpGreaterThan |
  *           OpLessThanOrEquals OpGreaterThanOrEquals | OpAnd | OpOr */

/** Class representing the binary operator within a BinOppApp. */
abstract class BinOp {
  String name;
  public BinOp(String s) { name = s; }
  public String toString() { return name; }
  public abstract <ResType> ResType accept(BinOpVisitor<ResType> v);
}

/** Visitor for the BinOp union type. */
interface BinOpVisitor<ResType> {
  ResType forBinOpPlus();
  ResType forBinOpMinus();
  ResType forOpTimes();
  ResType forOpDivide();
  ResType forOpEquals();
  ResType forOpNotEquals();
  ResType forOpLessThan();
  ResType forOpGreaterThan();
  ResType forOpLessThanEquals();
  ResType forOpGreaterThanEquals();
  ResType forOpAnd();
  ResType forOpOr();
  ResType forOpGets();
}

class UnOpPlus extends UnOp {
  public static final UnOpPlus ONLY = new UnOpPlus();
  private UnOpPlus() { super("+"); }
  public <ResType> ResType accept(UnOpVisitor<ResType> v) {
    return v.forUnOpPlus(); 
  }
}

class UnOpMinus extends UnOp {
  public static final UnOpMinus ONLY = new UnOpMinus();
  private UnOpMinus() { super("-"); }
  public <ResType> ResType accept(UnOpVisitor<ResType> v) {
    return v.forUnOpMinus(); 
  }
}

class OpTilde extends UnOp {
  public static final OpTilde ONLY = new OpTilde();
  private OpTilde() { super("~"); }
  public <ResType> ResType accept(UnOpVisitor<ResType> v) {
    return v.forOpTilde(); 
  }
}

/** UnOp for dereference operator '!' */
class OpBang extends UnOp {
  public static final OpBang ONLY = new OpBang();
  private OpBang() { super("!"); }
  public <ResType> ResType accept(UnOpVisitor<ResType> v) {
    return v.forOpBang();
  }
}

/** UnOp for ref creation operator 'ref' */
class OpRef extends UnOp {
  public static final OpRef ONLY = new OpRef();
  private OpRef() { super("ref"); }
  public <ResType> ResType accept(UnOpVisitor<ResType> v) {
    return v.forOpRef();
  }
}

class BinOpPlus extends BinOp {
  public static final BinOpPlus ONLY = new BinOpPlus();
  private BinOpPlus() { super("+"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forBinOpPlus(); 
  }
}

class BinOpMinus extends BinOp {
  public static final BinOpMinus ONLY = new BinOpMinus();
  private BinOpMinus() { super("-"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forBinOpMinus(); 
  }
}

class OpTimes extends BinOp {
  public static final OpTimes ONLY = new OpTimes();
  private OpTimes() { super("*"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpTimes(); 
  }
}

class OpDivide extends BinOp {
  public static final OpDivide ONLY = new OpDivide();
  private OpDivide() { super("/"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpDivide(); 
  }
}

class OpEquals extends BinOp {
  public static final OpEquals ONLY = new OpEquals();
  private OpEquals() { super("="); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpEquals(); 
  }
}

class OpNotEquals extends BinOp {
  public static final OpNotEquals ONLY = new OpNotEquals();
  private OpNotEquals() { super("!="); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpNotEquals(); 
  }
}

class OpLessThan extends BinOp {
  public static final OpLessThan ONLY = new OpLessThan();
  private OpLessThan() { super("<"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpLessThan(); 
  }
}

class OpGreaterThan extends BinOp {
  public static final OpGreaterThan ONLY = new OpGreaterThan();
  private OpGreaterThan() { super(">"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpGreaterThan(); 
  }
}

class OpLessThanEquals extends BinOp {
  public static final OpLessThanEquals ONLY = new OpLessThanEquals();
  private OpLessThanEquals() { super("<="); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpLessThanEquals(); 
  }
}

class OpGreaterThanEquals extends BinOp {
  public static final OpGreaterThanEquals ONLY = new OpGreaterThanEquals();
  private OpGreaterThanEquals() { super(">="); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpGreaterThanEquals(); 
  }
}

class OpAnd extends BinOp {
  public static final OpAnd ONLY = new OpAnd();
  private OpAnd() { super("&"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpAnd(); 
  }
}

class OpOr extends BinOp {
  public static final OpOr ONLY = new OpOr();
  private OpOr() { super("|"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpOr(); 
  }
}

/** BinOp for assignment operator '<-' */
class OpGets extends BinOp {
  public static final OpGets ONLY = new OpGets();
  private OpGets() { super("<-"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpGets();
  }
}

/* UnOpApp is a Term because it does not need enclosing parentheses when appearing in a binary expression */
class UnOpApp implements Term {
  private UnOp rator;
  private AST arg;

  UnOpApp(UnOp r, AST a) { rator = r; arg = a; }

  public UnOp rator() { return rator; }
  public AST arg() { return arg; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forUnOpApp(this); }
  public String toString() { return rator + " " + arg; }
}

class BinOpApp implements Term {
  private BinOp rator;
  private AST arg1, arg2;

  BinOpApp(BinOp r, AST a1, AST a2) { rator = r; arg1 = a1; arg2 = a2; }

  public BinOp rator() { return rator; }
  public AST arg1() { return arg1; }
  public AST arg2() { return arg2; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forBinOpApp(this); }
  public String toString() {
    return "(" + toString(arg1) + " " + rator + " " + toString(arg2) + ")"; 
  }
  private String toString(AST arg) {
    String argString = arg.toString();
    if (! (arg instanceof Term)) return "(" + argString + ")";
    else return argString;
  }
}

class Map implements AST {
  private Variable[] vars;
  private JamType[] types;  // param type annotations (may be null for untyped)
  private AST body;

  Map(Variable[] v, AST b) { vars = v; types = null; body = b; }
  Map(Variable[] v, JamType[] t, AST b) { vars = v; types = t; body = b; }

  public Variable[] vars() { return vars; }
  public JamType[] types() { return types; }
  public AST body() { return body; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forMap(this); }
  public String toString() {
    return "map " + ToString.toString(vars, ",") + " to " + body;
  }
}  

class App implements Term {
  private AST rator;
  private AST[] args;

  App(AST r, AST[] a) { rator = r; args = a; }

  public AST rator() { return rator; }
  public AST[] args() { return args; }

  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forApp(this); }
  public String toString() { 
    if ((rator instanceof PrimFun) || (rator instanceof Variable))
      return rator + "(" + ToString.toString(args,", ") + ")"; 
    else
      return "(" +  rator + ")(" + ToString.toString(args,", ") + ")"; 
  }
}  

class If implements AST {
  private AST test, conseq, alt;
  If(AST t, AST c, AST a) { test = t; conseq = c; alt = a; }

  public AST test() { return test; }
  public AST conseq() { return conseq; }
  public AST alt() { return alt; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forIf(this); }
  public String toString() { 
    return "if " + test + " then " + conseq + " else " + alt ; 
  }
}  

class Let implements AST {
  private Def[] defs;
  private AST body;
  Let(Def[] d, AST b) { defs = d; body = b; }

  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forLet(this); }
  public Def[] defs() { return defs; }
  public AST body() { return body; }
  public String toString() { 
    return "let " + ToString.toString(defs," ") + " in " + body; 
  }

  /* Commonly used non-essential methods */
  /** Returns the vars that are locally defined in this Let. */
  public Variable[] vars() {
    int n = defs.length;
    Variable[] vars = new Variable[n];
    for(int i = 0; i < n; i++) { vars[i] = defs[i].lhs(); }
    return vars;
  }
  /** Returns the exps that appear on the rhs of defs in this Let. */
  public AST[] exps() {
    int n = defs.length;
    AST[] exps = new AST[n];
    for(int i = 0; i < n; i++) { exps[i] = defs[i].rhs(); }
    return exps;
  }
}

/** A Block is a non-empty sequence of statements (expressions) that returns the value of the last
  * statement (expression).  The preceding statements are included solely for their side-effect
  * (changes to the values stored in boxes)
  * Hence, a block cannot appear as the first argument in a binary operation unless it is
  * enclosed in parentheses. The empty block is a parser error (ParseException).
  */
class Block implements AST {
  private AST[] exps;
  public Block(AST[] es) {
    exps = es;
  }

  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forBlock(this); }

  public AST[] exps() { return exps; }

  public String toString() {
    return "{" + ToString.toString(exps, "; ") + "}";
  }
}


/** Def class representing a definition embedded inside a Let. */
class Def {
  private Variable lhs;
  private JamType type;  // type annotation (may be null for untyped)
  private AST rhs;

  Def(Variable l, AST r) { lhs = l; type = null; rhs = r; }
  Def(Variable l, JamType t, AST r) { lhs = l; type = t; rhs = r; }

  public Variable lhs() { return lhs; }
  public JamType type() { return type; }
  public AST rhs() { return rhs; }

  public String toString() {
    if (type != null) return lhs + ": " + type + " := " + rhs + ";";
    return lhs + " := " + rhs + ";";
  }
}

/** Dummy class containing an improved toString method for arrays. */
class ToString {

  public static String toString(Object[] a, String s) {
    StringBuffer result = new StringBuffer();
    for (int i = 0; i < a.length; i++) {
      if (i > 0) result.append(s);
      Object elt = a[i];
      String eltString = (elt instanceof Object[]) ?
        toString((Object[]) elt, s) : elt.toString();
      result.append(eltString);
    }
    return result.toString();
  }
}

/* ============================================================
 *  JamType hierarchy for Typed Jam (Assignment 5)
 * ============================================================ */

/** Interface for Jam types. */
interface JamType {
  boolean equals(Object other);
  String toString();
}

/** Singleton class for the integer type. */
class IntType implements JamType {
  public static final IntType ONLY = new IntType();
  private IntType() {}
  public boolean equals(Object o) { return o instanceof IntType; }
  public int hashCode() { return 1; }
  public String toString() { return "int"; }
}

/** Singleton class for the boolean type. */
class BoolType implements JamType {
  public static final BoolType ONLY = new BoolType();
  private BoolType() {}
  public boolean equals(Object o) { return o instanceof BoolType; }
  public int hashCode() { return 2; }
  public String toString() { return "bool"; }
}

/** Singleton class for the unit type. */
class UnitType implements JamType {
  public static final UnitType ONLY = new UnitType();
  private UnitType() {}
  public boolean equals(Object o) { return o instanceof UnitType; }
  public int hashCode() { return 3; }
  public String toString() { return "unit"; }
}

/** Class for list types: list elemType. */
class ListType implements JamType {
  private JamType elemType;
  ListType(JamType t) { elemType = t; }
  public JamType elemType() { return elemType; }
  public boolean equals(Object o) {
    if (!(o instanceof ListType)) return false;
    return elemType.equals(((ListType) o).elemType);
  }
  public int hashCode() { return 7 + elemType.hashCode(); }
  public String toString() { return "list " + elemType; }
}

/** Class for reference types: ref elemType. */
class RefType implements JamType {
  private JamType elemType;
  RefType(JamType t) { elemType = t; }
  public JamType elemType() { return elemType; }
  public boolean equals(Object o) {
    if (!(o instanceof RefType)) return false;
    return elemType.equals(((RefType) o).elemType);
  }
  public int hashCode() { return 11 + elemType.hashCode(); }
  public String toString() { return "ref " + elemType; }
}

/** Class for function types: (params -> result). */
class FunType implements JamType {
  private JamType[] params;
  private JamType result;
  FunType(JamType[] p, JamType r) { params = p; result = r; }
  public JamType[] params() { return params; }
  public JamType result() { return result; }
  public boolean equals(Object o) {
    if (!(o instanceof FunType)) return false;
    FunType f = (FunType) o;
    if (params.length != f.params.length) return false;
    for (int i = 0; i < params.length; i++) {
      if (!params[i].equals(f.params[i])) return false;
    }
    return result.equals(f.result);
  }
  public int hashCode() {
    int h = result.hashCode();
    for (JamType p : params) h = 31 * h + p.hashCode();
    return h;
  }
  public String toString() {
    return "(" + ToString.toString(params, ", ") + " -> " + result + ")";
  }
}

/** Typed Jam Interpreter (Assignment 5).
  * Supports two evaluation strategies:
  *   eagerEval() - call-by-value/eager (value/value)
  *   lazyEval()  - call-by-value/lazy  (value/need)
  * Both methods run the parser, context-sensitive syntax checker, type checker, and then evaluate.
  */

import java.io.IOException;
import java.io.Reader;
import java.util.HashMap;

/** Exception thrown when a Jam program has a type error. */
class TypeException extends RuntimeException {
  TypeException(String msg) { super(msg); }
}

/** Exception thrown during Jam evaluation (run-time errors). */
class EvalException extends RuntimeException {
  EvalException(String msg) { super(msg); }
}

/** Interpreter class for Typed Jam. Exposes only eagerEval() and lazyEval(). */
class Interpreter {
  /** Parser to use. */
  Parser parser;

  /** Parsed (and syntax-checked) AST. */
  AST prog;

  Interpreter(String fileName) throws IOException {
    parser = new Parser(fileName);
    prog = parser.parseAndCheck();
  }

  Interpreter(Parser p) {
    parser = p;
    prog = parser.parseAndCheck();
  }

  Interpreter(Reader reader) {
    parser = new Parser(reader);
    prog = parser.parseAndCheck();
  }

  /* ----------------------------------------------------------------
   * Public API
   * ---------------------------------------------------------------- */

  /** Type-checks then evaluates using call-by-value/eager (value/value). */
  public JamVal eagerEval() {
    checkTypes(prog);
    return prog.accept(valueValueVisitor);
  }

  /** Type-checks then evaluates using call-by-value/lazy (value/need). */
  public JamVal lazyEval() {
    checkTypes(prog);
    return prog.accept(valueNeedVisitor);
  }

  /* ----------------------------------------------------------------
   * Type Checker
   * ---------------------------------------------------------------- */

  /** Type-checks the given AST.  Throws TypeException if any type error is found. */
  private void checkTypes(AST ast) {
    ast.accept(new TypeCheckVisitor(new HashMap<Variable, JamType>()));
  }

  /** Visitor that type-checks a Typed Jam AST.  Returns the type of each expression. */
  static class TypeCheckVisitor implements ASTVisitor<JamType> {

    /** Type environment: maps variables to their declared types. */
    private HashMap<Variable, JamType> env;

    TypeCheckVisitor(HashMap<Variable, JamType> e) { env = e; }

    /** Returns a new TypeCheckVisitor with vars[i] -> types[i] added. */
    private TypeCheckVisitor extend(Variable[] vars, JamType[] types) {
      HashMap<Variable, JamType> newEnv = new HashMap<Variable, JamType>(env);
      for (int i = 0; i < vars.length; i++) {
        newEnv.put(vars[i], types[i]);
      }
      return new TypeCheckVisitor(newEnv);
    }

    /* ----- Visitor methods ----- */

    public JamType forIntConstant(IntConstant i) { return IntType.ONLY; }

    public JamType forBoolConstant(BoolConstant b) { return BoolType.ONLY; }

    /** Typed empty: empty : ElemType has type list ElemType. */
    public JamType forEmptyConstant(EmptyConstant n) {
      JamType elem = n.elemType();
      if (elem == null)
        throw new TypeException("empty must have a type annotation in Typed Jam");
      return new ListType(elem);
    }

    public JamType forVariable(Variable v) {
      JamType t = env.get(v);
      if (t == null)
        throw new TypeException("Unbound variable " + v);
      return t;
    }

    /** PrimFun as a standalone expression is illegal in Typed Jam. */
    public JamType forPrimFun(PrimFun f) {
      throw new TypeException("Primitive `" + f + "' cannot be used as a standalone value");
    }

    public JamType forUnOpApp(UnOpApp u) {
      final JamType argType = u.arg().accept(this);
      return u.rator().accept(new UnOpVisitor<JamType>() {
        public JamType forUnOpPlus() {
          if (!(argType instanceof IntType))
            throw new TypeException("Unary + requires int, got " + argType);
          return IntType.ONLY;
        }
        public JamType forUnOpMinus() {
          if (!(argType instanceof IntType))
            throw new TypeException("Unary - requires int, got " + argType);
          return IntType.ONLY;
        }
        public JamType forOpTilde() {
          if (!(argType instanceof BoolType))
            throw new TypeException("~ requires bool, got " + argType);
          return BoolType.ONLY;
        }
        public JamType forOpBang() {
          if (!(argType instanceof RefType))
            throw new TypeException("! requires a ref type, got " + argType);
          return ((RefType) argType).elemType();
        }
        public JamType forOpRef() {
          return new RefType(argType);
        }
      });
    }

    public JamType forBinOpApp(BinOpApp b) {
      final JamType t1 = b.arg1().accept(this);
      final JamType t2 = b.arg2().accept(this);
      return b.rator().accept(new BinOpVisitor<JamType>() {
        public JamType forBinOpPlus()  { checkBothInt(t1, t2, "+");  return IntType.ONLY; }
        public JamType forBinOpMinus() { checkBothInt(t1, t2, "-");  return IntType.ONLY; }
        public JamType forOpTimes()    { checkBothInt(t1, t2, "*");  return IntType.ONLY; }
        public JamType forOpDivide()   { checkBothInt(t1, t2, "/");  return IntType.ONLY; }
        public JamType forOpLessThan()         { checkBothInt(t1, t2, "<");  return BoolType.ONLY; }
        public JamType forOpGreaterThan()      { checkBothInt(t1, t2, ">");  return BoolType.ONLY; }
        public JamType forOpLessThanEquals()   { checkBothInt(t1, t2, "<="); return BoolType.ONLY; }
        public JamType forOpGreaterThanEquals(){ checkBothInt(t1, t2, ">="); return BoolType.ONLY; }
        public JamType forOpAnd() { checkBothBool(t1, t2, "&"); return BoolType.ONLY; }
        public JamType forOpOr()  { checkBothBool(t1, t2, "|"); return BoolType.ONLY; }
        public JamType forOpEquals() {
          if (!t1.equals(t2))
            throw new TypeException("= requires both operands to have the same type, got " + t1 + " and " + t2);
          return BoolType.ONLY;
        }
        public JamType forOpNotEquals() {
          if (!t1.equals(t2))
            throw new TypeException("!= requires both operands to have the same type, got " + t1 + " and " + t2);
          return BoolType.ONLY;
        }
        public JamType forOpGets() {
          if (!(t1 instanceof RefType))
            throw new TypeException("<- requires a ref on the left, got " + t1);
          JamType inner = ((RefType) t1).elemType();
          if (!t2.equals(inner))
            throw new TypeException("<- type mismatch: ref " + inner + " but assigned " + t2);
          return UnitType.ONLY;
        }
      });
    }

    public JamType forApp(App a) {
      AST rator = a.rator();
      final AST[] args = a.args();

      // Primitive function application
      if (rator instanceof PrimFun) {
        return checkPrimApp((PrimFun) rator, args);
      }

      // User-defined function application
      JamType ratorType = rator.accept(this);
      if (!(ratorType instanceof FunType))
        throw new TypeException("Applied expression has non-function type " + ratorType);
      FunType funType = (FunType) ratorType;
      JamType[] params = funType.params();
      if (params.length != args.length)
        throw new TypeException("Function expects " + params.length + " argument(s), given " + args.length);
      for (int i = 0; i < params.length; i++) {
        JamType argType = args[i].accept(this);
        if (!argType.equals(params[i]))
          throw new TypeException("Argument " + i + " has type " + argType +
                                  " but parameter requires " + params[i]);
      }
      return funType.result();
    }

    public JamType forMap(Map m) {
      JamType[] paramTypes = m.types();
      Variable[] vars = m.vars();
      if (paramTypes == null)
        throw new TypeException("map parameters must have type annotations in Typed Jam");
      TypeCheckVisitor newVisitor = extend(vars, paramTypes);
      JamType bodyType = m.body().accept(newVisitor);
      return new FunType(paramTypes, bodyType);
    }

    public JamType forIf(If i) {
      JamType testType = i.test().accept(this);
      if (!(testType instanceof BoolType))
        throw new TypeException("if condition must be bool, got " + testType);
      JamType conseqType = i.conseq().accept(this);
      JamType altType = i.alt().accept(this);
      if (!conseqType.equals(altType))
        throw new TypeException("if branches have different types: " + conseqType + " and " + altType);
      return conseqType;
    }

    public JamType forLet(Let l) {
      Def[] defs = l.defs();
      int n = defs.length;

      // Gather declared types for all variables (for recursive let)
      Variable[] allVars = new Variable[n];
      JamType[] allTypes = new JamType[n];
      for (int i = 0; i < n; i++) {
        allVars[i] = defs[i].lhs();
        allTypes[i] = defs[i].type();
        if (allTypes[i] == null)
          throw new TypeException("Missing type annotation for " + allVars[i]);
      }

      // Extend the environment with all declared types (supports mutual recursion)
      TypeCheckVisitor newVisitor = extend(allVars, allTypes);

      // Check each rhs against its declared type
      for (int i = 0; i < n; i++) {
        JamType rhsType = defs[i].rhs().accept(newVisitor);
        if (!rhsType.equals(allTypes[i]))
          throw new TypeException("let binding `" + allVars[i] + "' declared as " +
                                  allTypes[i] + " but right-hand side has type " + rhsType);
      }

      return l.body().accept(newVisitor);
    }

    public JamType forBlock(Block b) {
      AST[] exps = b.exps();
      JamType last = null;
      for (AST exp : exps) last = exp.accept(this);
      return last;
    }

    /* ----- Helpers ----- */

    private void checkBothInt(JamType t1, JamType t2, String op) {
      if (!(t1 instanceof IntType) || !(t2 instanceof IntType))
        throw new TypeException("`" + op + "' requires both operands to be int, got " +
                                t1 + " and " + t2);
    }

    private void checkBothBool(JamType t1, JamType t2, String op) {
      if (!(t1 instanceof BoolType) || !(t2 instanceof BoolType))
        throw new TypeException("`" + op + "' requires both operands to be bool, got " +
                                t1 + " and " + t2);
    }

    /** Type-checks a primitive function application. */
    private JamType checkPrimApp(PrimFun prim, final AST[] args) {
      return prim.accept(new PrimFunVisitor<JamType>() {
        public JamType forConsPrim() {
          if (args.length != 2)
            throw new TypeException("cons expects 2 arguments, given " + args.length);
          JamType elemType = args[0].accept(TypeCheckVisitor.this);
          JamType listType = args[1].accept(TypeCheckVisitor.this);
          if (!(listType instanceof ListType))
            throw new TypeException("Second argument to cons must be a list, got " + listType);
          JamType expected = ((ListType) listType).elemType();
          if (!elemType.equals(expected))
            throw new TypeException("cons: element type mismatch: got " + elemType +
                                    " but list has element type " + expected);
          return listType;
        }
        public JamType forFirstPrim() {
          if (args.length != 1)
            throw new TypeException("first expects 1 argument, given " + args.length);
          JamType t = args[0].accept(TypeCheckVisitor.this);
          if (!(t instanceof ListType))
            throw new TypeException("first: argument must be a list, got " + t);
          return ((ListType) t).elemType();
        }
        public JamType forRestPrim() {
          if (args.length != 1)
            throw new TypeException("rest expects 1 argument, given " + args.length);
          JamType t = args[0].accept(TypeCheckVisitor.this);
          if (!(t instanceof ListType))
            throw new TypeException("rest: argument must be a list, got " + t);
          return t;
        }
        public JamType forEmptyPPrim() {
          if (args.length != 1)
            throw new TypeException("empty? expects 1 argument, given " + args.length);
          JamType t = args[0].accept(TypeCheckVisitor.this);
          if (!(t instanceof ListType))
            throw new TypeException("empty?: argument must be a list, got " + t);
          return BoolType.ONLY;
        }
        public JamType forConsPPrim() {
          if (args.length != 1)
            throw new TypeException("cons? expects 1 argument, given " + args.length);
          JamType t = args[0].accept(TypeCheckVisitor.this);
          if (!(t instanceof ListType))
            throw new TypeException("cons?: argument must be a list, got " + t);
          return BoolType.ONLY;
        }
        // These should have been rejected at parse time, but guard anyway:
        public JamType forFunctionPPrim() {
          throw new TypeException("function? is not available in Typed Jam");
        }
        public JamType forNumberPPrim() {
          throw new TypeException("number? is not available in Typed Jam");
        }
        public JamType forListPPrim() {
          throw new TypeException("list? is not available in Typed Jam");
        }
        public JamType forRefPPrim() {
          throw new TypeException("ref? is not available in Typed Jam");
        }
        public JamType forArityPrim() {
          throw new TypeException("arity is not available in Typed Jam");
        }
      });
    }
  }

  /* ================================================================
   * Evaluation machinery (internal)
   * ================================================================ */

  /** Binding policy interface. */
  interface BindingPolicy {
    Binding newBinding(Variable var, AST ast, EvalVisitor ev);
    Binding newDummyBinding(Variable var);
  }

  /** Cons policy interface. */
  interface ConsPolicy {
    JamVal evalCons(AST[] args, EvalVisitor ev);
  }

  /** Call-by-value binding. */
  static class ValueBinding extends Binding {
    ValueBinding(Variable v, JamVal jv) { super(v, jv); }
    public JamVal value() {
      if (value == null) illegalForwardReference(var());
      return value;
    }
    public void setBinding(Suspension s) { value = s.eval(); }
    public String toString() { return "[" + var + ", " + value + "]"; }
  }

  /** Call-by-name binding. */
  static class NameBinding extends Binding {
    protected Suspension susp;
    NameBinding(Variable v, Suspension s) { super(v, null); susp = s; }
    public JamVal value() { return (susp == null) ? illegalForwardReference(var()) : susp.eval(); }
    public void setBinding(Suspension s) { susp = s; }
    public String toString() { return "[" + var + ", " + susp + "]"; }
  }

  /** Call-by-need binding. */
  static class NeedBinding extends NameBinding {
    NeedBinding(Variable v, Suspension s) { super(v, s); }
    public JamVal value() {
      if (value == null) {
        if (susp == null) illegalForwardReference(var());
        else { value = susp.eval(); susp = null; }
      }
      return value;
    }
    public void setBinding(AST exp, EvalVisitor ev) { susp = new ConcreteSuspension(exp, ev); value = null; }
    public String toString() { return "[" + var + ", " + value + ", " + susp + "]"; }
  }

  static JamVal illegalForwardReference(Variable v) {
    throw new EvalException("Attempt to evaluate variable " + v + " bound to null (illegal forward reference)");
  }

  static final BindingPolicy CALL_BY_VALUE = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new ValueBinding(var, arg.accept(ev));
    }
    public Binding newDummyBinding(Variable var) { return new ValueBinding(var, null); }
  };

  static final BindingPolicy CALL_BY_NEED = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NeedBinding(var, new ConcreteSuspension(arg, ev));
    }
    public Binding newDummyBinding(Variable var) { return new NeedBinding(var, null); }
  };

  /** Concrete suspension (unevaluated expression + evaluator). */
  static class ConcreteSuspension implements Suspension {
    private AST exp;
    private EvalVisitor ev;
    ConcreteSuspension(AST a, EvalVisitor e) { exp = a; ev = e; }
    AST exp() { return exp; }
    EvalVisitor ev() { return ev; }
    void putEv(EvalVisitor e) { ev = e; }
    public JamVal eval() { return exp.accept(ev); }
    public String toString() { return "<" + exp + ", " + ev + ">"; }
  }

  /** Lazy cons (call-by-need). */
  static class JamLazyNeedCons extends JamCons {
    private Suspension firstSusp;
    private Suspension restSusp;
    JamLazyNeedCons(AST f, AST r, EvalVisitor ev) {
      super(null, null);
      firstSusp = new ConcreteSuspension(f, ev);
      restSusp  = new ConcreteSuspension(r, ev);
    }
    public JamVal first() {
      if (first == null) { first = firstSusp.eval(); firstSusp = null; }
      return first;
    }
    public JamList rest() {
      if (rest == null) { rest = checkList(restSusp.eval()); restSusp = null; }
      return (JamList) rest;
    }
  }

  /** Eager cons policy. */
  static final ConsPolicy EAGER = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) {
      JamVal val0 = args[0].accept(ev);
      JamVal val1 = args[1].accept(ev);
      if (val1 instanceof JamList) return new JamCons(val0, (JamList) val1);
      throw new EvalException("Second argument " + val1 + " to `cons' is not a JamList");
    }
  };

  /** Call-by-need lazy cons policy. */
  static final ConsPolicy LAZYNEED = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) { return new JamLazyNeedCons(args[0], args[1], ev); }
  };

  /** Value-value evaluator (eager binding + eager cons). */
  static final ASTVisitor<JamVal> valueValueVisitor = new EvalVisitor(CALL_BY_VALUE, EAGER);

  /** Value-need evaluator (eager binding + lazy-need cons). */
  static final ASTVisitor<JamVal> valueNeedVisitor  = new EvalVisitor(CALL_BY_VALUE, LAZYNEED);

  /** Primary evaluation visitor. */
  static class EvalVisitor implements ASTVisitor<JamVal> {

    PureList<Binding> env;
    BindingPolicy bindingPolicy;
    ConsPolicy consPolicy;

    private EvalVisitor(PureList<Binding> e, BindingPolicy bp, ConsPolicy cp) {
      env = e; bindingPolicy = bp; consPolicy = cp;
    }

    EvalVisitor(BindingPolicy bp, ConsPolicy cp) { this(new Empty<Binding>(), bp, cp); }

    EvalVisitor newEvalVisitor(PureList<Binding> env) {
      return new EvalVisitor(env, bindingPolicy, consPolicy);
    }

    PureList<Binding> env() { return env; }

    public JamVal forBoolConstant(BoolConstant b) { return b; }
    public JamVal forIntConstant(IntConstant i)   { return i; }
    public JamVal forEmptyConstant(EmptyConstant n) { return JamEmpty.ONLY; }

    public JamVal forVariable(Variable v) {
      Binding match = env.accept(new LookupVisitor<Binding>(v));
      if (match == null) throw new EvalException("variable " + v + " is unbound");
      return match.value();
    }

    public JamVal forPrimFun(PrimFun f) { return f; }

    public JamVal forUnOpApp(UnOpApp u) {
      return u.rator().accept(new UnOpEvaluator(u.arg().accept(this)));
    }

    public JamVal forBinOpApp(BinOpApp b) {
      return b.rator().accept(new BinOpEvaluator(b.arg1(), b.arg2()));
    }

    public JamVal forApp(App a) {
      JamVal rator = a.rator().accept(this);
      if (rator instanceof JamFun)
        return ((JamFun) rator).accept(new FunEvaluator(a.args()));
      throw new EvalException(rator + " is not a valid function");
    }

    public JamVal forMap(Map m) { return new JamClosure(m, env); }

    public JamVal forIf(If i) {
      JamVal test = i.test().accept(this);
      if (!(test instanceof BoolConstant)) throw new EvalException("non-Boolean test in if");
      if (test == BoolConstant.TRUE) return i.conseq().accept(this);
      return i.alt().accept(this);
    }

    public JamVal forBlock(Block b) {
      AST[] exps = b.exps();
      JamVal result = null;
      for (AST exp : exps) result = exp.accept(this);
      return result;
    }

    public JamVal forLet(Let l) {
      Variable[] vars = l.vars();
      AST[] exps = l.exps();
      int n = vars.length;
      PureList<Binding> newEnv = env();
      Binding[] bindings = new Binding[n];
      for (int i = 0; i < n; i++) {
        bindings[i] = bindingPolicy.newDummyBinding(vars[i]);
        newEnv = newEnv.cons(bindings[i]);
      }
      EvalVisitor newEV = newEvalVisitor(newEnv);
      for (int i = 0; i < n; i++) {
        bindings[i].setBinding(new ConcreteSuspension(exps[i], newEV));
      }
      return l.body().accept(newEV);
    }

    /* ----- Inner classes for evaluation ----- */

    class FunEvaluator implements JamFunVisitor<JamVal> {
      AST[] args;
      FunEvaluator(AST[] asts) { args = asts; }

      PrimFunVisitor<JamVal> primEvaluator = new PrimFunVisitor<JamVal>() {
        private JamVal[] evalArgs() {
          JamVal[] vals = new JamVal[args.length];
          for (int i = 0; i < args.length; i++) vals[i] = args[i].accept(EvalVisitor.this);
          return vals;
        }
        private void primFunError(String fn) {
          throw new EvalException("Primitive `" + fn + "' applied to " + args.length + " arguments");
        }
        private JamCons evalJamConsArg(AST arg, String fun) {
          JamVal val = arg.accept(EvalVisitor.this);
          if (val instanceof JamCons) return (JamCons) val;
          throw new EvalException("Primitive `" + fun + "' applied to non-cons " + val);
        }

        public JamVal forFunctionPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("function?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamFun);
        }
        public JamVal forNumberPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("number?");
          return BoolConstant.toBoolConstant(vals[0] instanceof IntConstant);
        }
        public JamVal forListPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("list?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamList);
        }
        public JamVal forConsPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("cons?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamCons);
        }
        public JamVal forEmptyPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("empty?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamEmpty);
        }
        public JamVal forRefPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("ref?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamRef);
        }
        public JamVal forConsPrim() {
          if (args.length != 2) primFunError("cons");
          return consPolicy.evalCons(args, EvalVisitor.this);
        }
        public JamVal forArityPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("arity");
          if (!(vals[0] instanceof JamFun)) throw new EvalException("arity applied to non-function");
          return ((JamFun) vals[0]).accept(new JamFunVisitor<IntConstant>() {
            public IntConstant forJamClosure(JamClosure jc) { return new IntConstant(jc.code().vars().length); }
            public IntConstant forPrimFun(PrimFun jpf) { return new IntConstant(jpf instanceof ConsPrim ? 2 : 1); }
          });
        }
        public JamVal forFirstPrim() {
          if (args.length != 1) primFunError("first");
          return evalJamConsArg(args[0], "first").first();
        }
        public JamVal forRestPrim() {
          if (args.length != 1) primFunError("rest");
          return evalJamConsArg(args[0], "rest").rest();
        }
      };

      public JamVal forJamClosure(JamClosure closure) {
        Map map = closure.code();
        Variable[] vars = map.vars();
        int n = args.length;
        if (vars.length != n) throw new EvalException("closure applied to " + n + " arguments");
        PureList<Binding> newEnv = closure.env();
        for (int i = 0; i < n; i++) {
          newEnv = newEnv.cons(bindingPolicy.newBinding(vars[i], args[i], EvalVisitor.this));
        }
        return map.body().accept(newEvalVisitor(newEnv));
      }

      public JamVal forPrimFun(PrimFun primFun) { return primFun.accept(primEvaluator); }
    }

    static class UnOpEvaluator implements UnOpVisitor<JamVal> {
      private JamVal val;
      UnOpEvaluator(JamVal jv) { val = jv; }

      private IntConstant checkInteger(String op) {
        if (val instanceof IntConstant) return (IntConstant) val;
        throw new EvalException("Unary `" + op + "' applied to non-integer " + val);
      }
      private BoolConstant checkBoolean(String op) {
        if (val instanceof BoolConstant) return (BoolConstant) val;
        throw new EvalException("Unary `" + op + "' applied to non-boolean " + val);
      }
      private JamRef checkRef(String op) {
        if (val instanceof JamRef) return (JamRef) val;
        throw new EvalException("Unary `" + op + "' applied to non-ref " + val);
      }

      public JamVal forUnOpPlus()  { return checkInteger("+"); }
      public JamVal forUnOpMinus() { return new IntConstant(-checkInteger("-").value()); }
      public JamVal forOpTilde()   { return checkBoolean("~").not(); }
      public JamVal forOpBang()    { return checkRef("!").value(); }
      public JamVal forOpRef()     { return new JamRef(val); }
    }

    class BinOpEvaluator implements BinOpVisitor<JamVal> {
      private AST arg1, arg2;
      BinOpEvaluator(AST a1, AST a2) { arg1 = a1; arg2 = a2; }

      private IntConstant evalIntegerArg(AST arg, String b) {
        JamVal val = arg.accept(EvalVisitor.this);
        if (val instanceof IntConstant) return (IntConstant) val;
        throw new EvalException("Binary `" + b + "' applied to non-integer " + val);
      }
      private BoolConstant evalBooleanArg(AST arg, String b) {
        JamVal val = arg.accept(EvalVisitor.this);
        if (val instanceof BoolConstant) return (BoolConstant) val;
        throw new EvalException("Binary `" + b + "' applied to non-boolean " + val);
      }

      public JamVal forBinOpPlus()  { return new IntConstant(evalIntegerArg(arg1,"+").value() + evalIntegerArg(arg2,"+").value()); }
      public JamVal forBinOpMinus() { return new IntConstant(evalIntegerArg(arg1,"-").value() - evalIntegerArg(arg2,"-").value()); }
      public JamVal forOpTimes()    { return new IntConstant(evalIntegerArg(arg1,"*").value() * evalIntegerArg(arg2,"*").value()); }
      public JamVal forOpDivide() {
        int d = evalIntegerArg(arg2,"/").value();
        if (d == 0) throw new EvalException("Division by zero");
        return new IntConstant(evalIntegerArg(arg1,"/").value() / d);
      }
      public JamVal forOpEquals()         { return BoolConstant.toBoolConstant(arg1.accept(EvalVisitor.this).equals(arg2.accept(EvalVisitor.this))); }
      public JamVal forOpNotEquals()      { return BoolConstant.toBoolConstant(!arg1.accept(EvalVisitor.this).equals(arg2.accept(EvalVisitor.this))); }
      public JamVal forOpLessThan()       { return BoolConstant.toBoolConstant(evalIntegerArg(arg1,"<").value() < evalIntegerArg(arg2,"<").value()); }
      public JamVal forOpGreaterThan()    { return BoolConstant.toBoolConstant(evalIntegerArg(arg1,">").value() > evalIntegerArg(arg2,">").value()); }
      public JamVal forOpLessThanEquals() { return BoolConstant.toBoolConstant(evalIntegerArg(arg1,"<=").value() <= evalIntegerArg(arg2,"<=").value()); }
      public JamVal forOpGreaterThanEquals() { return BoolConstant.toBoolConstant(evalIntegerArg(arg1,">=").value() >= evalIntegerArg(arg2,">=").value()); }
      public JamVal forOpAnd() {
        BoolConstant b1 = evalBooleanArg(arg1,"&");
        if (b1 == BoolConstant.FALSE) return BoolConstant.FALSE;
        return evalBooleanArg(arg2,"&");
      }
      public JamVal forOpOr() {
        BoolConstant b1 = evalBooleanArg(arg1,"|");
        if (b1 == BoolConstant.TRUE) return BoolConstant.TRUE;
        return evalBooleanArg(arg2,"|");
      }
      public JamVal forOpGets() {
        JamVal v1 = arg1.accept(EvalVisitor.this);
        if (!(v1 instanceof JamRef)) throw new EvalException("<- applied to non-ref " + v1);
        JamVal v2 = arg2.accept(EvalVisitor.this);
        ((JamRef) v1).setValue(v2);
        return JamUnit.ONLY;
      }
    }
  }
}

/** Jam lexer class for all assignments.              
  * Given a Lexer object, the next token in that input stream being processed by the Lexer is returned by the
  * readToken() method; it throws a ParseException (a form of RuntimeException) if it encounters a syntax error.  
  * Calling readToken() advances the cursor in the input stream to the next token.
  * 
  * The method peek() in the Lexer class has the same behavior as readToken() except for the fact that it does not
  * advance the cursor.
  */

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.InputStreamReader;
import java.io.IOException;
import java.io.Reader;
import java.io.StreamTokenizer;
import java.util.HashMap;

class Lexer extends StreamTokenizer {

  /* short names for StreamTokenizer codes */

  public static final int WORD = StreamTokenizer.TT_WORD; 
  public static final int NUMBER = StreamTokenizer.TT_NUMBER; 
  public static final int EOF = StreamTokenizer.TT_EOF; 
  public static final int EOL = StreamTokenizer.TT_EOL; 

  /* operator Tokens */

  // <unop>  ::= <sign> | ~   | ! 
  // <binop> ::= <sign> | "*" | / | = | != | < | > | <= | >= | & | "|" | <- 
  // <sign>  ::= "+" | -

  //  Note: there is no class distinction between <unop> and <binop> at 
  //  lexical level because of ambiguity; <sign> belongs to both

  public static final OpToken PLUS = OpToken.newBothOpToken(UnOpPlus.ONLY, BinOpPlus.ONLY); 
  public static final OpToken MINUS = OpToken.newBothOpToken(UnOpMinus.ONLY, BinOpMinus.ONLY);
  public static final OpToken TIMES = OpToken.newBinOpToken(OpTimes.ONLY);
  public static final OpToken DIVIDE = OpToken.newBinOpToken(OpDivide.ONLY);
  public static final OpToken EQUALS = OpToken.newBinOpToken(OpEquals.ONLY);
  public static final OpToken NOT_EQUALS = OpToken.newBinOpToken(OpNotEquals.ONLY);
  public static final OpToken LESS_THAN = OpToken.newBinOpToken(OpLessThan.ONLY);
  public static final OpToken GREATER_THAN = OpToken.newBinOpToken(OpGreaterThan.ONLY);
  public static final OpToken LESS_THAN_EQUALS = OpToken.newBinOpToken(OpLessThanEquals.ONLY);
  public static final OpToken GREATER_THAN_EQUALS = OpToken.newBinOpToken(OpGreaterThanEquals.ONLY);
  public static final OpToken NOT = OpToken.newUnOpToken(OpTilde.ONLY);
  public static final OpToken AND = OpToken.newBinOpToken(OpAnd.ONLY);
  public static final OpToken OR = OpToken.newBinOpToken(OpOr.ONLY);

  /* Used to support reference cells. */
  public static final OpToken BANG = OpToken.newUnOpToken(OpBang.ONLY);
  public static final OpToken GETS = OpToken.newBinOpToken(OpGets.ONLY);
  public static final OpToken REF = OpToken.newUnOpToken(OpRef.ONLY);

  /* Type keywords for Typed Jam (Assignment 5). */
  public static final KeyWord UNIT_TYPE = new KeyWord("unit");
  public static final KeyWord INT_TYPE  = new KeyWord("int");
  public static final KeyWord BOOL_TYPE = new KeyWord("bool");
  public static final KeyWord LIST_TYPE = new KeyWord("list");

  /* Keywords */

  public static final KeyWord IF     = new KeyWord("if");
  public static final KeyWord THEN   = new KeyWord("then");
  public static final KeyWord ELSE   = new KeyWord("else");
  public static final KeyWord LET    = new KeyWord("let");
//  public static final KeyWord LETREC = new KeyWord("letrec");   // Used to support separate letrec construction
  public static final KeyWord IN     = new KeyWord("in");
  public static final KeyWord MAP    = new KeyWord("map");
  public static final KeyWord TO     = new KeyWord("to");
  public static final KeyWord BIND   = new KeyWord(":=");

  /* fields */

  /** The Reader from which this lexer reads. */
  public final Reader rdr;

  /* The wordtable for classifying words in token stream */
  public HashMap<String,Token>  wordTable = new HashMap<String,Token>();

  /** The buffer holding the next token in the intput stream; it is used to support the peek() operation, which cannot
    * be implemented using StreamTokenizer pushBack because some Tokens are composed of two StreamTokenizer tokens. */
  Token buffer;

  /* constructors */

  /** Constructs a Lexer for the specified inputStream */
  Lexer(Reader inputStream) {
    super(new BufferedReader(inputStream));
    rdr = inputStream;
    initLexer();
  }

  /** Constructor that uses a File as the input stream. */
  Lexer(String fileName) throws IOException {
    this(new FileReader(fileName));
  }

  /* Initializes lexer tables and the StreamTokenizer that the lexer extends */
  private void initLexer() {

    // configure StreamTokenizer portion of this
    resetSyntax();
    parseNumbers();
    ordinaryChar('-');
    slashSlashComments(true);
    wordChars('0', '9');
    wordChars('a', 'z');
    wordChars('A', 'Z');
    wordChars('_', '_');
    wordChars('?', '?');
    whitespaceChars(0, ' '); 

    // `+' `-' `*' `/' `~' `=' `<' `>' `&' `|' `:' `;' `,' '!'
    // `(' `)' `[' `]' are ordinary characters (self-delimiting)

    initWordTable();
    buffer = null;  // buffer initially empty
  }

  /** Resets the reader embedded in this lexer.  The same file may be scanned multiple times in tests. */
  public void reset() throws ParseException { 
    try { rdr.reset(); }
    catch(IOException e) { throw new ParseException(e); }
  }

  /** Reads tokens until next end-of-line */
  public void flush() throws IOException {
    eolIsSignificant(true);
    while (nextToken() != EOL) ; // eat tokens until EOL
    eolIsSignificant(false);
  }

  /** Returns the next token in the input stream without consuming it */
  public Token peek() { 
    if (buffer == null) buffer = readToken();
    return buffer;
  }

  /** Reads the next token as defined by StreamTokenizer in the input stream (consuming it). */
  private int getToken() {
    // synonymous with nextToken() except for throwing an unchecked 
    // ParseException instead of a checked IOException
    try {
      int tokenType = nextToken();
      return tokenType;
    } catch(IOException e) {
      throw new ParseException("IOException " + e + "thrown by nextToken()");
    }
  }

  /** Reads the next Token in the input stream (consuming it) */
  public Token readToken() {

    /* Uses getToken() to read next token and constructs the Token object representing that token.
     * NOTE: token representations for all Token classes except IntConstant are unique; a HashMap 
     * is used to avoid duplication.  Hence, == can safely be used to compare all Tokens except 
     * IntConstants for equality (assuming that code does not gratuitously create Tokens).  When the
     * stream is reduced to EOT, returns null instead of a Token.
     */

    if (buffer != null) {
      Token token = buffer;
      buffer = null;          // clear buffer
      return token;
    }

    int tokenType = getToken();

    switch (tokenType) {

      case NUMBER:
        int value = (int) nval;
        if (nval == (double) value) return new IntConstant(value);
        throw new ParseException("The number " + nval + " is not a 32 bit integer");
      case WORD:
        Token regToken = wordTable.get(sval);
        if (regToken == null) {
          // must be new variable name
          Variable newVar = new Variable(sval);
          wordTable.put(sval, newVar);
          return newVar;
        }
        return regToken;

      case EOF: return EndOfFile.ONLY;
      case '(': return LeftParen.ONLY;
      case ')': return RightParen.ONLY;
      case '[': return LeftBrack.ONLY;
      case ']': return RightBrack.ONLY;
      case '{': return LeftBrace.ONLY;
      case '}': return RightBrace.ONLY;
      case ',': return Comma.ONLY;
      case ';': return SemiColon.ONLY;

      case '+': return PLUS;
      case '-': {
        tokenType = getToken();
        if (tokenType == '>') return Arrow.ONLY;
        pushBack();
        return MINUS;
      }
      case '*': return TIMES;
      case '/': return DIVIDE;  
      case '~': return NOT;  
      case '=': return EQUALS;

      case '<':
        tokenType = getToken();
        if (tokenType == '=') return LESS_THAN_EQUALS;
        if (tokenType == '-') return GETS;    // Used to support reference cells
        pushBack();
        return LESS_THAN; 

      case '>': 
        tokenType = getToken();
        if (tokenType == '=') return GREATER_THAN_EQUALS;  
        pushBack();
        return GREATER_THAN;

      case '!':
        tokenType = getToken();
        if (tokenType == '=') return NOT_EQUALS;
        pushBack();
        return BANG;  // Used to support reference cells 

      case '&': return AND;  
      case '|': return OR;  
      case ':': {
        tokenType = getToken();
        if (tokenType == '=') return BIND;   // ":=" is a keyword
        pushBack();
        return Colon.ONLY;   // ':' used for type annotations in Typed Jam
      }
      default:  
        throw new 
        ParseException("'" + ((char) tokenType) + "' is not a legal token");
    }
  }

  /** Initializes the table of Strings used to recognize Tokens */
  private void initWordTable() {
    // initialize wordTable

    // constants
    // <empty>  ::= empty
    // <bool>  ::= true | false

    wordTable.put("empty", EmptyConstant.ONLY);
    wordTable.put("true",  BoolConstant.TRUE);
    wordTable.put("false", BoolConstant.FALSE); 

    // Install primitive functions // (and unary operator named "ref" which is added in Assignment 4)
    // <prim>  ::= number? | function? | list? | empty? | cons? | ref? | arity | cons | first | rest 
    // Note: ref? is added in Assignment 4

    wordTable.put("number?",   NumberPPrim.ONLY);
    wordTable.put("function?", FunctionPPrim.ONLY);
    wordTable.put("list?",     ListPPrim.ONLY);
    wordTable.put("empty?",    EmptyPPrim.ONLY);
    wordTable.put("cons?",     ConsPPrim.ONLY);
    wordTable.put("ref?",      RefPPrim.ONLY);  // Supports the addition of reference cells
    wordTable.put("ref",       REF);            // Supports the addition of reference cells
    wordTable.put("arity",     ArityPrim.ONLY);  
    wordTable.put("cons",      ConsPrim.ONLY);
    wordTable.put("first",     FirstPrim.ONLY);
    wordTable.put("rest",      RestPrim.ONLY);


    // keywords: if then else let in map to :=
    wordTable.put("if",   Lexer.IF);
    wordTable.put("then", Lexer.THEN);
    wordTable.put("else", Lexer.ELSE);
    wordTable.put("let",  Lexer.LET);
    wordTable.put("in",   Lexer.IN);
    wordTable.put("map",  Lexer.MAP);
    wordTable.put("to",   Lexer.TO);

    // Type keywords for Typed Jam (Assignment 5)
    wordTable.put("unit", UNIT_TYPE);
    wordTable.put("int",  INT_TYPE);
    wordTable.put("bool", BOOL_TYPE);
    wordTable.put("list", LIST_TYPE);
  }
}

/** Parser for Typed Jam (Assignment 5).
  * Key changes from Assignment 4:
  *  - Definitions and map parameters require type annotations: Id : Type
  *  - empty must be followed by : Type
  *  - PrimFun must be applied (can no longer appear standalone)
  *  - Removed primitives: list?, number?, function?, ref?, arity
  *  - Added type grammar: unit | int | bool | list Type | ref Type | (TypeList -> Type)
  */

import java.io.*;
import java.util.*;

/** Class that represents parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
  ParseException(Throwable t) { super(t); }
}

/** Helper pair class for a typed variable (variable + type). */
class TypedVarPair {
  Variable[] vars;
  JamType[] types;
  TypedVarPair(Variable[] v, JamType[] t) { vars = v; types = t; }
}

class Parser {

  private Lexer in;

  Parser(Lexer i) { in = i; }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  public void initParser() { }

  /** Parses the program in the Lexer associated with this. */
  public AST parse() throws ParseException {
    try {
      in.reset();
      AST prog = parseExp();
      Token t = in.readToken();
      if (t == EndOfFile.ONLY) return prog;
      else throw new ParseException("Legal program followed by extra token " + t);
    }
    finally {
      try { in.rdr.close(); }
      catch (IOException e) { throw new ParseException(e); }
    }
  }

  /** Parses and syntactically checks the program in the Lexer associated with this. */
  public AST parseAndCheck() throws ParseException {
    AST prog = parseExp();
    Token t = in.readToken();
    if (t != EndOfFile.ONLY) throw new ParseException("Legal program '" + prog + "'followed by extra token " + t);

    /* Invoke the CheckVisitor to confirm prog does not contain free variables or duplicate names. */
    prog.accept(CheckVisitor.INITIAL);   // aborts on an error by throwing an exception
    return prog;
  }

  /** Parses:
    *   <exp> ::= if <exp> then <exp> else <exp>
    *           | let <prop-def-list> in <exp>
    *           | map TypedIdList to <exp>
    *           | { PropStatementList }
    *           | <term> { <binop> <term> }*
    */
  private AST parseExp() {
    Token token = in.readToken();

    if (token == Lexer.IF) return parseIf();
    if (token == Lexer.LET) return parseLet();
    if (token == Lexer.MAP) return parseMap();

    /* Supports the addition of blocks to Jam */
    if (token == LeftBrace.ONLY) {
      AST[] exps = parseExps(SemiColon.ONLY, RightBrace.ONLY);
      if (exps.length == 0) throw new ParseException("Illegal empty block");
      return new Block(exps);
    }

    /* phrase begins with a term */
    AST exp = parseTerm(token);

    Token next = in.peek();
    while (next instanceof OpToken) {
      OpToken op = (OpToken) next;
      in.readToken(); // remove next from input stream
      if (! (op.isBinOp())) error(next, "binary operator");
      AST newTerm = parseTerm(in.readToken());
      exp = new BinOpApp(op.toBinOp(), exp, newTerm);
      next = in.peek();
    }
    return exp;
  }

  /** Parses a term in the typed grammar:
    *   <term> ::= <unop> <term>
    *            | Prim ( <exp-list> )        -- primitive applied to args
    *            | empty : Type               -- typed empty list
    *            | <factor> { ( <exp-list> ) } -- optional application
    *            | <int>
    *            | <bool>
    */
  private AST parseTerm(Token token) {

    /* Unary operator */
    if (token instanceof OpToken) {
      OpToken op = (OpToken) token;
      if (! op.isUnOp()) error(op, "unary operator");
      return new UnOpApp(op.toUnOp(), parseTerm(in.readToken()));
    }

    /* Typed empty: empty : Type */
    if (token == EmptyConstant.ONLY) {
      Token colon = in.readToken();
      if (colon != Colon.ONLY) error(colon, "`:' after `empty'");
      JamType elemType = parseType();
      return new EmptyConstant(elemType);
    }

    /* Primitive function must be applied: Prim ( ExpList ) */
    if (token instanceof PrimFun) {
      PrimFun prim = (PrimFun) token;
      // Check for disallowed primitives
      if (prim == FunctionPPrim.ONLY || prim == NumberPPrim.ONLY ||
          prim == ListPPrim.ONLY     || prim == RefPPrim.ONLY    ||
          prim == ArityPrim.ONLY) {
        throw new ParseException("Primitive `" + prim + "' is not supported in Typed Jam");
      }
      // Allowed prims: cons, first, rest, empty?, cons?
      Token next = in.readToken();
      if (next != LeftParen.ONLY) error(next, "`(' after primitive `" + prim + "'");
      AST[] args = parseArgs();  // includes closing paren
      return new App(prim, args);
    }

    /* Integer or boolean constant */
    if (token instanceof Constant) return (Constant) token;

    /* Factor optionally followed by application */
    AST factor = parseFactor(token);
    Token next = in.peek();
    if (next == LeftParen.ONLY) {
      in.readToken();  // consume '('
      AST[] exps = parseArgs();  // includes closing paren
      return new App(factor, exps);
    }
    return factor;
  }

  /** Parses: <factor> ::= ( <exp> ) | Id
    * Note: PrimFun is NOT a valid Factor in Typed Jam; it must be applied in parseTerm.
    */
  private AST parseFactor(Token token) {

    if (token == LeftParen.ONLY) {
      AST exp = parseExp();
      Token t = in.readToken();
      if (t != RightParen.ONLY) error(t, "`)'");
      return exp;
    }

    if (token instanceof Variable) return (Variable) token;

    error(token, "variable or `('");
    return null; // unreachable
  }

  /** Parses `if <exp> then <exp> else <exp>' given that `if' has already been read. */
  private AST parseIf() {
    AST test = parseExp();
    Token key1 = in.readToken();
    if (key1 != Lexer.THEN) error(key1, "`then'");
    AST conseq = parseExp();
    Token key2 = in.readToken();
    if (key2 != Lexer.ELSE) error(key2, "`else'");
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses `let <prop-def-list> in <exp>' given that `let' has already been read. */
  private AST parseLet() {
    Def[] defs = parseDefs();
    AST body = parseExp();
    return new Let(defs, body);
  }

  /** Parses `map TypedIdList to <exp>' given that `map' has already been read. */
  private AST parseMap() {
    TypedVarPair tvp = parseTypedVars();  // reads up to and including `to'
    AST body = parseExp();
    return new Map(tvp.vars, tvp.types, body);
  }

  /** Parses a comma-or-semicolon separated list of expressions followed by a delimiter.
    *   <exp-list> ::= <empty> | <prop-exp-list>
    *   <prop-exp-list> ::= <exp> | <exp> sep <prop-exp-list>
    */
  private AST[] parseExps(Token separator, Token delim) {
    LinkedList<AST> exps = new LinkedList<AST>();
    Token next = in.peek();

    if (next == delim) {
      in.readToken(); // consume delimiter
      return new AST[0];
    }

    do {
      AST exp = parseExp();
      exps.addLast(exp);
      next = in.readToken();
    } while (next == separator);

    if (next != delim) error(next, "`,' or `)'");
    return (AST[]) exps.toArray(new AST[0]);
  }

  private AST[] parseArgs() { return parseExps(Comma.ONLY, RightParen.ONLY); }

  /** Parses typed parameter list for `map':
    *   TypedIdList ::= { PropTypedIdList }
    *   PropTypedIdList ::= TypedId | TypedId, PropTypedIdList
    *   TypedId ::= Id : Type
    * NOTE: consumes `to' following the list.
    */
  private TypedVarPair parseTypedVars() {
    LinkedList<Variable> vars = new LinkedList<Variable>();
    LinkedList<JamType> types = new LinkedList<JamType>();

    Token t = in.readToken();
    if (t == Lexer.TO) {
      // empty param list
      return new TypedVarPair(new Variable[0], new JamType[0]);
    }

    do {
      if (! (t instanceof Variable)) error(t, "variable");
      Variable v = (Variable) t;

      Token colon = in.readToken();
      if (colon != Colon.ONLY) error(colon, "`:' after variable name");

      JamType typ = parseType();
      vars.addLast(v);
      types.addLast(typ);

      t = in.readToken();
      if (t == Lexer.TO) break;
      if (t != Comma.ONLY) error(t, "`to' or `,'");
      t = in.readToken();
    } while (true);

    return new TypedVarPair(
      vars.toArray(new Variable[0]),
      types.toArray(new JamType[0])
    );
  }

  /** Parses a proper (non-empty) list of definitions:
    *   prop-def-list ::= def | def prop-def-list
    *   def ::= Id : Type := Exp ;
    * NOTE: consumes `in' following the definitions.
    */
  private Def[] parseDefs() {
    LinkedList<Def> defs = new LinkedList<Def>();
    Token t = in.readToken();

    do {
      Def d = parseDef(t);
      defs.addLast(d);
      t = in.readToken();
    } while (t != Lexer.IN);

    return (Def[]) defs.toArray(new Def[0]);
  }

  /** Parses `Id : Type := Exp ;' given that the first token (Id) has been read. */
  private Def parseDef(Token var) {
    if (! (var instanceof Variable)) error(var, "variable");
    Variable v = (Variable) var;

    Token colon = in.readToken();
    if (colon != Colon.ONLY) error(colon, "`:' after variable name");

    JamType typ = parseType();

    Token bind = in.readToken();
    if (bind != Lexer.BIND) error(bind, "`:='");

    AST exp = parseExp();

    Token semi = in.readToken();
    if (semi != SemiColon.ONLY) error(semi, "`;'");

    return new Def(v, typ, exp);
  }

  /** Parses a Type:
    *   Type ::= unit | int | bool | list Type | ref Type | (TypeList -> Type)
    */
  private JamType parseType() {
    Token t = in.readToken();

    if (t == Lexer.UNIT_TYPE) return UnitType.ONLY;
    if (t == Lexer.INT_TYPE)  return IntType.ONLY;
    if (t == Lexer.BOOL_TYPE) return BoolType.ONLY;

    if (t == Lexer.LIST_TYPE) {
      JamType elem = parseType();
      return new ListType(elem);
    }

    if (t == Lexer.REF) {
      JamType elem = parseType();
      return new RefType(elem);
    }

    if (t == LeftParen.ONLY) {
      // (TypeList -> Type)
      JamType[] params = parseTypeList();  // reads types until '->'
      Token arrow = in.readToken();
      if (arrow != Arrow.ONLY) error(arrow, "`->'");
      JamType result = parseType();
      Token rp = in.readToken();
      if (rp != RightParen.ONLY) error(rp, "`)'");
      return new FunType(params, result);
    }

    error(t, "type (unit, int, bool, list, ref, or `(')");
    return null; // unreachable
  }

  /** Parses a comma-separated list of types, stopping before `->'.
    *   TypeList ::= { PropTypeList }
    *   PropTypeList ::= Type | Type, PropTypeList
    */
  private JamType[] parseTypeList() {
    // If the next token is '->', the type list is empty
    if (in.peek() == Arrow.ONLY) {
      return new JamType[0];
    }
    LinkedList<JamType> types = new LinkedList<JamType>();
    do {
      types.addLast(parseType());
      Token next = in.peek();
      if (next == Arrow.ONLY) break;
      if (next == Comma.ONLY) {
        in.readToken(); // consume ','
      } else {
        error(next, "`,' or `->'");
      }
    } while (true);
    return types.toArray(new JamType[0]);
  }

  private AST error(Token found, String expected) {
    throw new ParseException("Token `" + found + "' appears where " + expected + " was expected");
  }

  /** A legacy "main" method. */
  public static void main(String[] args) throws IOException {
    if (args.length == 0) return;
    Parser p = new Parser(args[0]);
    AST prog = p.parse();
  }
}

/* JamVal and Token Data Definitions */

import java.util.NoSuchElementException;
  
/** A data object representing a Jam value.
  * JamVal := IntConstant | BoolConstant | JamList | JamFun */
interface JamVal {
  <ResType> ResType accept(JamValVisitor<ResType> jvv);
}

/** A visitor for the JamVal type (Jam values).  */
interface JamValVisitor<ResType> {
  ResType forIntConstant(IntConstant ji);
  ResType forBoolConstant(BoolConstant jb);
  ResType forJamList(JamList jl);
  ResType forJamFun(JamFun jf);
  ResType forJamRef(JamRef jr);
  ResType forJamUnit(JamUnit ju);
}

/** JamVal classes */

/** A Jam integer constant, also used to represent an integer token for parsing.  */
class IntConstant implements Token, Constant, JamVal {
  private int value;
  
  IntConstant(int i) { value = i; }
  // duplicates can occur!
  
  public int value() { return value; }
  
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forIntConstant(this); }
  public <ResType> ResType accept(JamValVisitor<ResType> v) { return v.forIntConstant(this); }
  /** redefines equals so that equal integers are recognized as equal */
  public boolean equals(Object other) {
    return (other != null && this.getClass() == other.getClass()) && 
      (value == ((IntConstant)other).value());
  }
  /** computes the obvious hashcode for this consistent with equals. */
  public int hashcode() { return value; }
  public String toString() { return String.valueOf(value); }
}

/** A Jam boolean constant, also used to represent a boolean token for parsing. */
class BoolConstant implements Token, Constant, JamVal {
  private boolean value;
  private BoolConstant(boolean b) { value = b; }
  
  /** Singleton pattern definitions. */
  public static final BoolConstant FALSE = new BoolConstant(false);
  public static final BoolConstant TRUE = new BoolConstant(true);
  
  /** A factory method that returns BoolConstant corresponding to b. It is atatic because
    * it does not depend on this. */
  public static BoolConstant toBoolConstant(boolean b) { 
    if (b) return TRUE; 
    else return FALSE;
  }
  
  public boolean value() { return value; }
  public BoolConstant not() { if (this == FALSE) return TRUE; else return FALSE; }
  
  public <ResType> ResType accept(ASTVisitor<ResType> av) { return av.forBoolConstant(this); }
  public <ResType> ResType accept(JamValVisitor<ResType> jv) { return jv.forBoolConstant(this); }
  public String toString() { return String.valueOf(value); }
}

/* Immutable List and Binding Classes */

/** Interface for all Pure Lists.
  * PureList<ElemType> := Empty<ElemType> | Cons<ElemType>
  */
interface PureList<ElemType> {
  abstract PureList<ElemType> cons(ElemType o);
  abstract PureList<ElemType> empty();
  abstract <ResType> ResType accept(PureListVisitor<ElemType, ResType> v);
    abstract boolean contains(ElemType e);
    abstract String toStringHelp();
  abstract PureList<ElemType> append(PureList<ElemType> addedElts);
}

/** The visitor interface for the type PureList<ElemType> */
interface PureListVisitor<ElemType, ResType> {
  ResType forEmpty(Empty<ElemType> e);
  ResType forCons(Cons<ElemType> c);
}

/** An abstract class that factors out code common to classes Empty<T> and Cons<T> */
abstract class PureListClass<ElemType> implements PureList<ElemType> {
  public PureList<ElemType> cons(ElemType o) { return new Cons<ElemType>(o,this); }
  public PureList<ElemType> empty() { return new Empty<ElemType>(); }
  public abstract <ResType> ResType accept(PureListVisitor<ElemType, ResType> v);  
  // preceding DICTATED BY BUG IN JSR-14
}

/** The empty PureList<T> class */
class Empty<ElemType> extends PureListClass<ElemType> {
  public <ResType> ResType accept(PureListVisitor<ElemType,ResType> v) { return v.forEmpty(this); }
  public PureList<ElemType> append(PureList<ElemType> addedElts) { return addedElts; }
  public boolean contains(ElemType e) { return false; }
  
  /** overrides inherited equals because Empty is not a singleton! */
  public boolean equals(Object other) { 
    return (other != null && other.getClass() == this.getClass());
  }
  
  public String toString() { return "()"; }
  public String toStringHelp() { return ""; }
}

/** The non-empty PureList<T> class */
class Cons<ElemType> extends PureListClass<ElemType> {
  ElemType first;
  PureList<ElemType> rest;
  Cons(ElemType f, PureList<ElemType> r) { first = f; rest = r; }
  
  public <ResType> ResType accept(PureListVisitor<ElemType,ResType> v) { return v.forCons(this); }
  public PureList<ElemType> append(PureList<ElemType> addedElts) { 
    return new Cons<ElemType>(first, rest.append(addedElts)); 
  }
  
  public ElemType first() { return first; }
  public PureList<ElemType> rest() { return rest; }
  public boolean contains(ElemType e) {
    if (first.equals(e)) return true;
    else return rest().contains(e);
  }
  
  /** Overrides inherited equals to perform structural equality testing. */
  public boolean equals(Object other) { 
    if (other == null || ! (other instanceof Cons)) return false;
    if (other == this) return true;
    Cons otherCons = (Cons) other;
    return first().equals(otherCons.first()) && rest().equals(otherCons.rest());
  }
  /** Overrides hash code in accord with equals. */
  public int hashCode() { return first().hashCode() + rest().hashCode(); }
  
  public String toString() { return "(" + first + rest.toStringHelp() + ")"; }
  public String toStringHelp() { return " " + first + rest.toStringHelp(); }
}

/** The Jam List class representing JamVals that are PureLists. 
  * JamList := JamEmpty | JamCons
  */
interface JamList extends PureList<JamVal>, JamVal {
  JamEmpty empty();
  JamCons cons(JamVal v);
  /** Helper method that returns the depth-bounded string representation of this list with a leading blank in front of
    * each element and no enclosing parentheses.  For lists longer than maxDepth, elipsis is printed instead of the 
    * elements. */
  String toStringHelp(int maxDepth);
}

/** A singleton class extending Empty<JamVal> representing the empty JamList. */
class JamEmpty extends Empty<JamVal> implements JamList {
  public static final JamEmpty ONLY = new JamEmpty();
  private JamEmpty() {}
  
  public JamEmpty empty() { return ONLY; }
  public JamCons cons(JamVal v) { return new JamCons(v, this); }
  public <ResType> ResType accept(JamValVisitor<ResType> v) { return v.forJamList(this); }
  
  public String toStringHelp(int maxDepth) { return ""; }
}

class JamCons extends Cons<JamVal> implements JamList {
  
  /** Maximum depth of printing the elements of a potentially lazy stream. */
  private static final int MAX_DEPTH = 1000;
  
  public JamCons(JamVal v, JamList vList) { super(v, vList); }
  
  /** Factory method that returns an empty list. */
  public JamEmpty empty() { return JamEmpty.ONLY; }
  
  /** Factory method that return a list consisting of cons(v, this). */
  public JamCons cons(JamVal v) { return new JamCons(v, this); }
  
  public <ResType> ResType accept(JamValVisitor<ResType> v) { return v.forJamList(this); }
  public JamList rest() { return (JamList) super.rest(); }
  
  /** Returns val if val is a JamList. Otherwise it throws an EvalException. */
  public static JamList checkList(JamVal val) {
    if (val instanceof JamList)  return (JamList)val;
    throw new EvalException("The second argument to lazy cons is `" + val + "' which is not a list");
  }
  
  /* Depth-bounded printing method which must be defined at this level so that ordinary JamCons nodes appearing
   * within lazy lists are printed correctly. */
  
  /** Return the depth-bounded string representation of this. */
  public String toString() { return "(" + first() + rest().toStringHelp(MAX_DEPTH) + ")"; }
  
  /** Return the depth-bounded string representation for this with a leading blank but no enclosing parentheses. */
  public String toStringHelp(int maxDepth) {
    if (maxDepth == 0)  return " ...";
    return " " + first() + rest().toStringHelp(maxDepth - 1);
  }
}

/* Important List Utilities defined by visitors */

/** Interface for classes with a variable field (Variable and the various Binding classes). This interface permits
  * the generic LookupVisitor below to operate on any subclass of PureList<T> where T implements WithVariable. */
interface WithVariable {
  /** Accessor for the variable. */
  Variable var();
}

/** A generalized lookup visitor class that returns the element matching the embedded var in a 
  * PureList<Elemtype extends WithVariable>. If no match found, returns null. */
class LookupVisitor<ElemType extends WithVariable> implements PureListVisitor<ElemType, ElemType> {
  /** Variable to look up. */
  Variable var;
  
  // Invariant: the lexer guarantees that there is only one Variable instance for a given name enabling == testing
  
  LookupVisitor(Variable v) { var = v; }
  
  /** Case for empty lists. */
  public ElemType forEmpty(Empty<ElemType> e) { return null; }
  
  /** Case for non-empty lists. */
  public ElemType forCons(Cons<ElemType> c) {
    ElemType e = c.first();
    if (var == e.var()) return e;
    return c.rest().accept(this);
  }
}

/* Other JamVal classes */

/** The class representing a Jam function (closure or primitive function). 
  * JamFun := JamClosure | PrimFun
  */
abstract class JamFun implements JamVal {
  public <ResType> ResType accept(JamValVisitor<ResType> jvv) { return jvv.forJamFun(this); }
  abstract public <ResType> ResType accept(JamFunVisitor<ResType> jfv);
}

/** The visitor interface for the JamFun type */
interface JamFunVisitor<ResType> {
  ResType forJamClosure(JamClosure c);
  ResType forPrimFun(PrimFun pf);
}

/** The Suspension interface for a potentially deferred JamVal. This interface is intentionally opaque. */
interface Suspension {
  JamVal eval();
}

/** The abstract Jam binding class required to define JamClosure.  Makes no commitment regarding when the RHSs of 
  * variable bindings are evaluated.  The setBinding method takes a Suspension as input; evaluation may be deferred. */
abstract class Binding implements WithVariable {
  Variable var;
  JamVal value;
  Binding(Variable v, JamVal jv) { 
    var = v; value = jv;
  }
  public Variable var() { return var; }
  
  /** Return the value of the binding which may require evaluation. */
  public JamVal value() { return value; }
  
  /** Sets the binding to the value of the specified by the Suspension s.  The Suspension s may be evaluated immediately
    * or delayed until value() is called depending on the Binding mechanism. */
  public abstract void setBinding(Suspension s);
}
 
/** The class representing a Jam Closure. */
class JamClosure extends JamFun {
  private Map code;
  private PureList<Binding> env;
  
  JamClosure(Map c, PureList<Binding> e) { code = c; env = e; }
  Map code() { return code; }
  PureList<Binding> env() { return env; }
  public <ResType> ResType accept(JamFunVisitor<ResType> jfv) { return jfv.forJamClosure(this); }
}

/** The class representing a Jam Primitive Function. 
  * PrimFun := FunctionPPrim | NumberPPrim | ListPPrim | ConsPPrim | EmptyPPrim | ArityPrim | ConsPrim | FirstPrim | RestPrim 
  */
abstract class PrimFun extends JamFun implements Token, Term {
  private String name;
  PrimFun(String n) { name = n; }
  public String name() { return name; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forPrimFun(this); }
  public <ResType> ResType accept(JamFunVisitor<ResType> v) { return v.forPrimFun(this); }
  abstract public <ResType> ResType accept(PrimFunVisitor<ResType> pfv);
  public String toString() { return name; }
}

///** A dummy Jam value used to implement recursive let. */
// class JamVoid implements JamVal {
//  public static final JamVoid ONLY = new JamVoid();
//  private JamVoid() {}
//  public <ResType> ResType accept(JamValVisitor<ResType> jvv) { return jvv.forJamVoid(this); }
//}

/** A visitor for the singleton PrimFun classes. */
interface PrimFunVisitor<ResType> {
  ResType forFunctionPPrim();
  ResType forNumberPPrim();
  ResType forListPPrim();
  ResType forConsPPrim();
  ResType forEmptyPPrim();
  ResType forRefPPrim();
  ResType forArityPrim();
  ResType forConsPrim();
  ResType forFirstPrim();
  ResType forRestPrim();
}

/* The singleton Classes Representing Primitive Function Values */

/** A singleton class representing the primitive operation 'function?'. */
class FunctionPPrim extends PrimFun {
  public static final FunctionPPrim ONLY = new FunctionPPrim();
  private FunctionPPrim() { super("function?"); }
  public <ResType> ResType accept(PrimFunVisitor<ResType> pfv) { return pfv.forFunctionPPrim(); }
}

/** A singleton class representing the primitive operation 'number?'. */
class NumberPPrim extends PrimFun {
  public static final NumberPPrim ONLY = new NumberPPrim();
  private NumberPPrim() { super("number?"); }
